parameters.text:
=Analyze the following Jira bug ticket and produce a structured analysis.

Ticket Key: {{ $json.Key }}
Summary: {{ $json.summary }}
Issue Type: {{ $json.issue_type }}
Priority (Jira): {{ $json.priority }}
Status: {{ $json.status }}
Components: {{ $json.components }}
Labels: {{ $json.labels }}

Description:
{{ $json.description }}

Return ONLY the JSON with EXACT fields defined in schema.
Do NOT add extra fields like summary, severity, etc.

=Write a professional Test Plan document based on the following bug analysis.

TICKET INFO:
Key: {{ $json.output.ticket_key }}
Summary: {{ $('Edit Fields').item.json.summary }}
Priority: {{ $json.output.priority_for_testing }}
Reporter: {{ $('Edit Fields').item.json.reporter }}
Description: {{ $('Edit Fields').item.json.description }}

ANALYST ASSESSMENT:
{{ JSON.stringify($('AI Analyst').item.json.output, null, 2) }}

=Generate detailed test cases for the following bug ticket based on the test plan and analyst assessment.

TICKET:
Key: {{ $json.output.ticket_key }}
Summary: {{ $('Fetch Jira Ticket').item.json.fields.summary }}
Description: {{ $('Fetch Jira Ticket').item.json.fields.description }}

ANALYST ASSESSMENT:
{{ JSON.stringify($('AI Analyst').item.json.output, null, 2) }}

TEST PLAN:
{{ JSON.stringify($('AI Test Plan Writer').item.json.output, null, 2) }}

parameters.jsonSchemaExample:
{
  "ticket_key": "VWO-6",
  "test_plan_title": "Test Plan: Shopping Cart Total Shows $0.00 After Applying Discount Code",
  "introduction": "This test plan covers verification of the shopping cart total calculation when discount codes are applied...",
  "scope": {
    "in_scope": [
      "Discount code application on carts with 3+ items",
      "Cart total calculation after discount",
      "Verification across item count boundaries (1, 2, 3, 4+)"
    ],
    "out_of_scope": [
      "Payment gateway integration",
      "Discount code creation/management in admin"
    ]
  },
  "test_objectives": [
    "Verify cart total correctly reflects 20% discount for 3+ items",
    "Confirm no regression on 1-2 item carts",
    "Validate edge cases around the 3-item threshold"
  ],
  "severity_priority": {
    "severity": "High",
    "priority": "P1",
    "business_impact": "Direct revenue loss and customer trust erosion",
    "urgency": "Immediate — block v2.4.1 release"
  },
  "test_strategy": [
    "Functional testing of discount code SAVE20",
    "Boundary testing at item count thresholds",
    "Regression testing on checkout flow",
    "Negative testing with invalid/expired codes"
  ],
  "entry_criteria": [
    "Bug fix deployed to staging/test environment",
    "Test data with various item counts available",
    "Discount code SAVE20 active in test environment"
  ],
  "exit_criteria": [
    "All test cases executed with pass rate >= 95%",
    "No Critical or High severity defects open",
    "Cart total displays correctly for all item count scenarios"
  ],
  "environment": {
    "browser": "Chrome 120",
    "os": "Windows 11",
    "env": "Production (reproduce), Staging (verify fix)"
  },
  "risks_and_mitigations": [
    {
      "risk": "Bug may affect other discount types not tested",
      "mitigation": "Extend test cases to cover fixed-amount and BOGO codes"
    }
  ],
  "deliverables": [
    "Test case document (Excel)",
    "Test execution report",
    "Bug verification sign-off"
  ]
}
